cds-views-009.codeExamples:
-- Layer 1: Interface View (raw data)
@VDM.viewType: #BASIC
@AbapCatalog.sqlViewName: 'ZISALESORD'
@EndUserText.label: 'Sales Order Interface View'
define view Z_I_SalesOrder
  as select from vbak
{
  vbeln as SalesOrder,
  kunnr as SoldToParty,
  erdat as CreationDate,
  netwr as NetValue,
  waerk as Currency
}

-- Layer 2: Composite View (joins multiple interface views)
@VDM.viewType: #COMPOSITE
@AbapCatalog.sqlViewName: 'ZCSALESCOMP'
@EndUserText.label: 'Sales Order Composite View'
define view Z_C_SalesOrderComposite
  as select from Z_I_SalesOrder as SalesOrder
  inner join Z_I_Customer as Customer
    on SalesOrder.SoldToParty = Customer.Customer
{
  SalesOrder.SalesOrder,
  SalesOrder.CreationDate,
  Customer.CustomerName,
  SalesOrder.NetValue
}

-- Layer 3: Consumption View (app-specific)
@VDM.viewType: #CONSUMPTION
@OData.publish: true
@AbapCatalog.sqlViewName: 'ZCSALESAPP'
@EndUserText.label: 'Sales Order App View'
define view Z_C_SalesOrder_App
  as select from Z_C_SalesOrderComposite
{
  @UI.lineItem: [{ position: 10 }]
  SalesOrder,
  @UI.lineItem: [{ position: 20 }]
  CustomerName,
  @UI.lineItem: [{ position: 30 }]
  @Semantics.amount.currencyCode: 'Currency'
  NetValue
}

