-- Step 1: Create Include structure
@EndUserText.label: 'Sales Order Extension'
extend view I_SalesOrder with Z_EX_SalesOrder
{
  -- Custom append fields from CI_VBAK
  vbak.zz_custom_field1 as CustomField1,
  vbak.zz_region as SalesRegion
}
-- Now I_SalesOrder automatically has custom fields
-- visible in all dependent views

-- Composite View with Aggregation
@VDM.viewType: #COMPOSITE
@Analytics.dataCategory: #CUBE
define view Z_CP_MonthlySales
  as select from Z_I_SalesOrder
{
  @Semantics.calendar.yearMonth: true
  left(CreationDate, 6) as YearMonth,
  SoldToParty,
  -- Aggregation
  @DefaultAggregation: #SUM
  sum(NetValue) as TotalSales,
  @DefaultAggregation: #COUNT
  count(*) as OrderCount
}
group by left(CreationDate, 6), SoldToParty

